  $('#bestScore').textContent=Math.max(...analyzed.map(o=>o.score));
  $('#pipelineValue').textContent=money(analyzed.filter(o=>!['Skipped','Client Lost','Payment Received'].includes(o.status)).reduce((s,o)=>s+o.budget,0));
