function generateProposal(){
  const o=opportunities.find(x=>x.id===Number($('#proposalOpportunity').value));if(!o)return;
  const fmt=$('#proposalFormat').value,name=resolvedUserName(),profileSkills=resumeProfile?.skills||[],opportunitySkills=o.skills?.length?o.skills:findSkills(`${o.title} ${o.brief}`),matched=opportunitySkills.filter(skill=>profileSkills.includes(skill));
  const strengths=(matched.length?matched:profileSkills).slice(0,3),portfolioInput=$('#portfolioInput').value.trim(),portfolioUrl=safeHttpUrl(resumeProfile?.portfolioUrl||''),question=$('#questionInput').value.trim()||'Which deliverables and outcome are most important in the first milestone?';
  const strengthsLine=strengths.length?`My relevant strengths include ${strengths.join(', ')}.`:'[Add 2–3 relevant strengths from your profile.]';
  const proofLine=portfolioInput?`A relevant example is ${portfolioInput}.`:portfolioUrl?`You can review my work here: ${portfolioUrl}`:'[Add one relevant portfolio example or portfolio URL.]';
  const deliveryLine=`I would start by confirming the priority outcome and deliverables, share a focused first direction for review, then prepare the agreed final assets and handoff files.`;
  const compact=`Hi ${o.client||'team'},\n\nI saw your requirement for ${o.title}. ${strengthsLine}\n\n${proofLine}\n\n${deliveryLine}\n\nOne useful question: ${question}\n\nBest,\n${name}`;
  const premium=`Hi ${o.client||'team'},\n\nI reviewed your requirement for ${o.title}. The brief calls for work that is clear, consistent, and ready to use—not just visually polished.\n\nRelevant fit:\n- ${strengths.length?strengths.join('\n- '):'[Add relevant strengths from your profile]'}\n\nPortfolio proof:\n${proofLine}\n\nProposed approach:\n1. Confirm the audience, priority outcome, and final deliverables.\n2. Share one focused direction early for useful feedback.\n3. Develop the approved direction into the required assets.\n4. Deliver organized final files and agreed handoff notes.\n\nOne question before I recommend the exact scope: ${question}\n\nIf this approach fits, I can prepare a milestone plan after the scope is confirmed.\n\nBest,\n${name}`;
  let out=fmt==='Short proposal'||fmt==='LinkedIn DM pitch'||fmt==='Fiverr buyer-request response'?compact:premium;
  if(fmt==='Retainer pitch')out=premium.replace('a project range', 'a monthly partnership range').replace('project range around','monthly retainer around');
  if(fmt==='Email pitch')out=`Subject: A focused approach to ${o.title}\n\n${premium}`;
  $('#proposalOutput').value=out;updateIdentityWarnings();const warnings=[];if(identityMissing())warnings.push('name');if(!strengths.length)warnings.push('relevant strengths');if(!portfolioInput&&!portfolioUrl)warnings.push('portfolio proof');$('#proposalDataWarning').hidden=!warnings.length;$('#proposalDataWarning').textContent=warnings.length?`Complete before sending: ${warnings.join(', ')}.`:'';toast(`${fmt} generated`);
}
