function cleanJobText(html=''){const doc=new DOMParser().parseFromString(html,'text/html');return (doc.body.textContent||'').replace(/\s+/g,' ').trim()}
function findPublicEmail(text=''){const match=text.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);return match?match[0]:''}
const designRoleKeywords=['graphic designer','visual designer','brand designer','marketing designer','creative designer','digital designer','social media designer','campaign designer','motion designer','video editor','ui visual designer','freelance designer','remote designer'];
