function searchTokens(value=''){return [...new Set(String(value).toLowerCase().split(/[^a-z0-9+#]+/).filter(token=>token.length>2))]}
function isDesignSearch(query=''){return /design|creative|brand|visual|motion|video editor|illustrat|photoshop|figma|canva/i.test(`${query} ${(resumeProfile?.targetRole||'')} ${(resumeProfile?.skills||[]).join(' ')}`)}
