function normalizeRemotive(job,query){const description=cleanJobText(job.description);return{id:`remotive-${job.id}`,source:'Remotive',sourceId:String(job.id),title:job.title,company:job.company_name||'Unknown company',location:job.candidate_required_location||'Remote',remote:true,url:safeHttpUrl(job.url),description,tags:job.tags||[],date:job.publication_date||'',type:job.job_type||'Remote job',salary:job.salary||'',email:findPublicEmail(description),score:0,query}}
