    const seenTitles=new Set(),seenUrls=new Set();jobs=jobs.filter(job=>{const titleKey=`${job.title}|${job.company}`.toLowerCase().replace(/\s+/g,' ').trim(),urlKey=job.url||'';if(seenTitles.has(titleKey)||(urlKey&&seenUrls.has(urlKey)))return false;seenTitles.add(titleKey);if(urlKey)seenUrls.add(urlKey);return true});jobs.forEach(job=>job.score=liveJobScore(job,query,expandedQueries));jobs.sort((a,b)=>b.score-a.score);
