function saveLiveJob(job){if(opportunities.some(o=>o.url===job.url)){toast('Already saved');return}opportunities.unshift({id:Date.now(),title:job.title,client:job.company,country:job.location,platform:job.source,type:job.type==='Remote job'?'Remote contract':'Full-time job',budget:0,brief:job.description,skills:findSkills(`${job.title} ${job.description}`).slice(0,5),skill:job.score,portfolio:70,credibility:72,competition:60,deadline:75,payment:65,longterm:65,remote:job.remote?100:50,international:85,clarity:80,status:'Saved',verified:false,url:job.url,deadlineText:'See listing'});persist();renderDashboard();toast('Saved to tracker')}
