function answerFormDraft(job){const raw=$('#formQuestions').value.trim();if(!raw){toast('Paste the form questions first');return}const questions=raw.split(/\n+/).filter(Boolean);const skills=(resumeProfile?.skills||findSkills(`${job.title} ${job.description}`)).slice(0,5).join(', ');const answers=questions.map((q,i)=>{const l=q.toLowerCase();let answer;if(/why|interest|motivat/.test(l))answer=`I’m interested because the ${job.title} role combines ${skills||'[add your relevant skills]'} with a clear opportunity to contribute to ${job.company}.`;else if(/year|experience/.test(l))answer=resumeProfile?.years?`I bring ${resumeProfile.years}+ years of relevant experience, with strengths in ${skills||'[add your verified skills]'}.`:'[Add your verified years of experience and one relevant example.]';else if(/portfolio|website|work sample/.test(l))answer=resumeProfile?.portfolioUrl?`Portfolio: ${safeHttpUrl(resumeProfile.portfolioUrl)}`:'[Add your most relevant portfolio or case-study URL here]';else if(/salary|rate|compensation|budget/.test(l))answer=resumeProfile?.minRate?`My reviewed minimum rate is ${resumeProfile.minRate}; I would confirm the final range after reviewing scope and responsibilities.`:'[Add your expected rate or salary range after reviewing the scope.]';else if(/available|start|notice/.test(l))answer=resumeProfile?.availability?`Availability: ${resumeProfile.availability}.`:'[Add your verified availability or notice period.]';else answer=`Draft response needed: connect your experience in ${skills||'[add relevant skills]'} to this specific requirement without making an unsupported claim.`;return `${i+1}. ${q}\n${answer}`}).join('\n\n');$('#formAnswerOutput').className='form-answer-output';$('#formAnswerOutput').textContent=answers}
function showView(name){$$('.view').forEach(v=>v.classList.remove('active'));$(`#${name}View`).classList.add('active');$$('.nav-item[data-view]').forEach(n=>n.classList.toggle('active',n.dataset.view===name));const titles={discover:'Good opportunities, minus the noise.',smart:'Your supervised opportunity engine.',tracker:'Keep every conversation moving.',studio:'Write like you read the brief.',email:'Nothing sends without your say-so.',pricing:'Charge for the value, not the anxiety.',profile:'Make the search fit you.'};$('#pageTitle').textContent=titles[name];if(name==='studio'||name==='email')updateIdentityWarnings()}

$$('.nav-item[data-view]').forEach(n=>n.onclick=()=>showView(n.dataset.view));
$('#liveSearchQuery').value=resumeProfile?.targetRole||resumeProfile?.roles?.[0]||'';$('#liveSearchQuery').oninput=updateGuidedSearches;$('#liveSearchType').onchange=updateGuidedSearches;$('#runLiveSearch').onclick=searchRealJobs;$('#importOpportunityFromSmart').onclick=()=>$('#opportunityDialog').showModal();updateGuidedSearches();
