$('#addOpportunity').onclick=()=>$('#opportunityDialog').showModal();
$('#opportunityForm').addEventListener('submit',e=>{
  if(e.submitter?.value==='cancel')return;
  e.preventDefault();
  const fd=new FormData(e.currentTarget),brief=window.ScopeSecurity.boundedText(fd.get('brief'),50000),budget=+fd.get('budget');
  const enteredUrl=String(fd.get('url')||'').trim(),sourceUrl=safeHttpUrl(enteredUrl);
  if(enteredUrl&&!sourceUrl){toast('Use a safe http or https opportunity URL');return}
  const clarity=brief.length>180?85:brief.length>80?68:42;
  const matchedSkills=findSkills(`${fd.get('title')} ${brief}`);
  const profileMatch=resumeProfile?calculateResumeMatch(`${fd.get('title')} ${brief}`):+fd.get('skill');
  opportunities.unshift({id:Date.now(),title:window.ScopeSecurity.boundedText(fd.get('title'),300),client:window.ScopeSecurity.boundedText(fd.get('client'),300),country:window.ScopeSecurity.boundedText(fd.get('country')||'Unknown',120),platform:fd.get('platform'),type:fd.get('type'),budget,brief,skills:matchedSkills.length?matchedSkills.slice(0,4):['Design','Creative'],skill:profileMatch,portfolio:+fd.get('portfolio'),credibility:fd.get('verified')?82:45,competition:60,deadline:/tomorrow|urgent|24 hour/i.test(brief)?28:72,payment:fd.get('verified')?90:42,longterm:/ongoing|monthly|retainer|long.term/i.test(brief)?90:48,remote:90,international:fd.get('country')&&fd.get('country').toLowerCase()!=='india'?95:55,clarity,status:'Saved',verified:!!fd.get('verified'),url:sourceUrl,deadlineText:'Confirm with client'});
  persist();e.currentTarget.reset();$('#opportunityDialog').close();renderDashboard();selectedId=opportunities[0].id;renderDetail();toast(resumeProfile?'Added with résumé-based matching':'Opportunity analyzed and added')
});
