function currentEmailDraft(){return{recipient:$('#emailTo').value.trim(),subject:$('#emailSubject').value.trim(),body:window.ScopeSecurity.boundedText($('#emailBody').value,50000)}}
function revokeEmailApproval(){if($('#approveEmail').checked)$('#approveEmail').checked=false;$('#openGmailDraft').disabled=true;window.ScopeCloudApproval?.saveEmailDraft(currentEmailDraft()).catch(()=>{})}
['#emailTo','#emailSubject','#emailBody'].forEach(id=>$(id).addEventListener('input',revokeEmailApproval));
$('#approveEmail').onchange=async()=>{if(!$('#approveEmail').checked){$('#openGmailDraft').disabled=true;await window.ScopeCloudApproval?.revokeEmailDraft('user_unchecked').catch(()=>{});return}if(identityMissing()){$('#approveEmail').checked=false;$('#openGmailDraft').disabled=true;updateIdentityWarnings();toast('Add your name in My Profile before approving');return}if(!window.ScopeCloudApproval?.isSignedIn()){$('#approveEmail').checked=false;$('#openGmailDraft').disabled=true;toast('Sign in before approving a draft');return}const result=await window.ScopeCloudApproval.approveEmailDraft(currentEmailDraft()).catch(()=>null);if(!result){$('#approveEmail').checked=false;$('#openGmailDraft').disabled=true;toast('Database approval failed');return}$('#openGmailDraft').disabled=false;toast('Exact draft approved and logged')};
$('#useProposalEmail').onclick=()=>{const o=opportunities.find(x=>x.id===Number($('#proposalOpportunity').value))||opportunities[0];if(!$('#proposalOutput').value){generateProposal()}$('#emailSubject').value=`Design support for ${o.title}`;$('#emailBody').value=$('#proposalOutput').value;revokeEmailApproval();updateIdentityWarnings();toast('Proposal imported for review')};
