$('#openGmailDraft').onclick=async()=>{const from=$('#emailFrom').value.trim(),to=$('#emailTo').value.trim(),subject=$('#emailSubject').value.trim(),body=$('#emailBody').value.trim();if(!$('#approveEmail').checked)return;if(identityMissing()){revokeEmailApproval();updateIdentityWarnings();toast('Add your name in My Profile before continuing');return}if(!/^\S+@\S+\.\S+$/.test(to)){toast('Add a valid recipient email');return}if(!subject||!body){toast('Subject and message are required');return}const verified=await window.ScopeCloudApproval?.verifyEmailDraft(currentEmailDraft()).catch(()=>false);if(!verified){revokeEmailApproval();toast('Draft changed or database approval is missing');return}const url=`https://mail.google.com/mail/u/?authuser=${encodeURIComponent(from)}&view=cm&fs=1&to=${encodeURIComponent(to)}&su=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;window.open(url,'_blank','noopener');await window.ScopeCloudApproval?.logComposeOpened().catch(()=>{});$('#approveEmail').checked=false;$('#openGmailDraft').disabled=true;toast('Approved draft opened in Gmail')};
$('#resumeFile').onchange=async e=>{const file=e.target.files?.[0];if(!file)return;$('#resumeFileLabel').textContent=file.name;$('#parseStatus').textContent='Reading your résumé locally…';try{const text=await readResumeFile(file);$('#resumeText').value=text;analyzeResumeText(text,file.name);$('#parseStatus').textContent='Profile ready. Your personalized searches are below.';toast('Résumé profile created')}catch(err){$('#parseStatus').textContent=err.message;toast('Could not read that résumé')}};
